    if (!released) {
      throw new Error(`No matching active lease found for ${args.ticket_id}.`)
    }

    await saveWorkflowState(workflow)

    return JSON.stringify(
      {
        released,
        active_leases: workflow.lane_leases,
      },
      null,
      2,
    )
  },
})

